import type { TextFieldProps } from '../TextField';
export type SingleTimeValue = string;
export type TimePickerProps = Pick<TextFieldProps, 'inputId' | 'inputClassName' | 'disabled' | 'fullWidth' | 'size' | 'name' | 'helperText' | 'value' | 'error' | 'disableMaxLength'> & {
    /**
     * Пользовательское имя класса
     */
    className?: string;
    /**
     * Идентификатор для автоматизированного тестирования
     */
    dataTestId?: string;
    /**
     * шаг изменения времени при стрелках вверх вниз на клавиатуре, а также отображение секунд и минут
     * по умолчанию 60 не показывает секунды
     * 1 показать секунды
     * 3600 изменять только часы
     */
    step?: string;
    /**
     * Скрывает иконку календаря в пикере которая отвечает за выпадающее меню выбора времени
     */
    hidePicker?: boolean;
    /**
     * Показывает плейсхолдер в пикере 00:00
     */
    showPlaceholder?: boolean;
    /**
     * Показывает иконку часы левее таймпикера
     */
    showIcon?: boolean;
    /**
     * Задаем начальное значение `value`
     */
    defaultValue?: string;
    /**
     * Обработчик вызываемый при изменении значения `value`
     */
    onChange?: (time: SingleTimeValue) => void;
};
